import React, { useState } from "react";
import "./BatchDashboard.css";

function BatchDashboard({ dashboardData, uploadedFile }) {
  const [downloadLoading, setDownloadLoading] = useState(false);

  if (!dashboardData || !dashboardData.batchResult) {
    return (
      <div className="batch-dashboard">
        <div className="no-data-message">
          <h3>No Batch Analysis Results Available</h3>
          <p>Please run a batch analysis first from the Batch Processing section.</p>
        </div>
      </div>
    );
  }

  const { batchResult } = dashboardData;
  const { dataset_info, risk_analysis, customer_segmentation, feature_analysis, sample_predictions, data_source } = batchResult;

  // Calculate percentages for risk distribution
  const totalCustomers = dataset_info.total_customers;
  const riskDistribution = risk_analysis.risk_distribution || {};

  // Function to download full dataset with predictions
  const downloadFullDataset = async () => {
    try {
      setDownloadLoading(true);
      
      // Check if we have the uploaded file
      if (!uploadedFile) {
        alert("Please upload a CSV file first to download the full report.");
        setDownloadLoading(false);
        return;
      }

      console.log("📥 Starting full report download...");
      console.log("📁 Uploaded file:", uploadedFile.name);
      
      const formData = new FormData();
      formData.append('file', uploadedFile);

      const response = await fetch('http://localhost:5000/api/batch/download-report', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || `HTTP error! status: ${response.status}`);
      }

      // Get the blob data
      const blob = await response.blob();
      
      // Create download link
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      
      // Get filename from response headers or use default
      const contentDisposition = response.headers.get('content-disposition');
      let filename = 'churn_analysis_full_report.csv';
      if (contentDisposition) {
        const filenameMatch = contentDisposition.match(/filename="(.+)"/);
        if (filenameMatch) {
          filename = filenameMatch[1];
        }
      }
      
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      
      // Clean up
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      console.log("✅ Full report download completed successfully");

    } catch (error) {
      console.error('❌ Error downloading full report:', error);
      alert(`Error downloading full report: ${error.message}`);
    } finally {
      setDownloadLoading(false);
    }
  };

  // Function to download sample template
  const downloadSampleTemplate = () => {
    const sampleData = [
      {
        Customer_ID: 'CUST_001',
        Tenure: 12,
        OrderCount: 8,
        CashbackAmount: 1500,
        DaySinceLastOrder: 7,
        HourSpendOnApp: 45,
        SatisfactionScore: 4,
        WarehouseToHome: 15,
        CityTier: 2,
        Complain: 0,
        OrderAmountHikeFromlastYear: 15,
        CouponUsed: 3,
        NumberOfDeviceRegistered: 2,
        NumberOfAddress: 2,
        PreferredLoginDevice: 'Mobile Phone',
        PreferredPaymentMode: 'Credit Card',
        PreferedOrderCat: 'Laptop & Accessory',
        Gender: 'Male',
        MaritalStatus: 'Married'
      },
      {
        Customer_ID: 'CUST_002',
        Tenure: 6,
        OrderCount: 3,
        CashbackAmount: 800,
        DaySinceLastOrder: 25,
        HourSpendOnApp: 25,
        SatisfactionScore: 3,
        WarehouseToHome: 30,
        CityTier: 1,
        Complain: 0,
        OrderAmountHikeFromlastYear: 10,
        CouponUsed: 1,
        NumberOfDeviceRegistered: 1,
        NumberOfAddress: 1,
        PreferredLoginDevice: 'Computer',
        PreferredPaymentMode: 'Debit Card',
        PreferedOrderCat: 'Mobile',
        Gender: 'Female',
        MaritalStatus: 'Single'
      }
    ];

    const csvHeaders = Object.keys(sampleData[0]).join(',');
    const csvRows = sampleData.map(row => 
      Object.values(row).map(value => 
        typeof value === 'string' && value.includes(',') ? `"${value}"` : value
      ).join(',')
    );
    
    const csvContent = [csvHeaders, ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'churn_analysis_template.csv';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);
  };

  return (
    <div className="batch-dashboard">
      <div className="dashboard-header">
        <div className="header-content">
          <h2>📊 Batch Analysis Dashboard</h2>
          <div className="data-source-badge">
            Data Source: <span className="source-type">{data_source === "demo" ? "Demo Data" : "Uploaded CSV"}</span>
          </div>
        </div>
        <div className="header-actions">
          <button 
            className="download-report-btn secondary"
            onClick={downloadSampleTemplate}
            title="Download CSV template with required columns"
          >
            <span className="btn-icon">📋</span>
            Download Template
          </button>
          <button 
            className="download-report-btn primary"
            onClick={downloadFullDataset}
            disabled={downloadLoading}
            title="Download complete dataset with all predictions and risk levels"
          >
            {downloadLoading ? (
              <>
                <div className="spinner small"></div>
                Downloading...
              </>
            ) : (
              <>
                <span className="btn-icon">📥</span>
                Download Complete Report
              </>
            )}
          </button>
        </div>
      </div>

      {/* Dataset Overview */}
      <div className="section-card dataset-overview">
        <h3>📁 Dataset Overview</h3>
        <div className="dataset-stats-grid">
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_customers}</div>
            <div className="stat-label">Total Customers</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.total_features}</div>
            <div className="stat-label">Features Analyzed</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{dataset_info.dataset_size_kb.toFixed(1)} KB</div>
            <div className="stat-label">Dataset Size</div>
          </div>
          <div className="stat-card">
            <div className="stat-value">{risk_analysis.total_predicted_churn}</div>
            <div className="stat-label">Predicted Churn</div>
          </div>
        </div>
        
        <div className="dataset-details">
          <div className="detail-item">
            <span className="detail-label">Imputation Strategy:</span>
            <span className="detail-value">{dataset_info.imputation_strategy}</span>
          </div>
          <div className="detail-item">
            <span className="detail-label">Numeric Features:</span>
            <span className="detail-value">{dataset_info.imputation_values_summary.numeric_features}</span>
          </div>
          <div className="detail-item">
            <span className="detail-label">Categorical Features:</span>
            <span className="detail-value">{dataset_info.imputation_values_summary.categorical_features}</span>
          </div>
        </div>
      </div>

      {/* Risk Analysis */}
      <div className="section-card risk-analysis">
        <h3>⚠️ Risk Analysis Summary</h3>
        <div className="risk-metrics-grid">
          <div className="risk-metric">
            <div className="metric-value">{risk_analysis.average_probability?.toFixed(3) || '0.000'}</div>
            <div className="metric-label">Average Churn Probability</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{((risk_analysis.churn_rate || 0) * 100).toFixed(1)}%</div>
            <div className="metric-label">Overall Churn Rate</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">{customer_segmentation.high_risk_customers || 0}</div>
            <div className="metric-label">High-Risk Customers</div>
          </div>
          <div className="risk-metric">
            <div className="metric-value">₹{(customer_segmentation.potential_revenue_loss || 0).toLocaleString()}</div>
            <div className="metric-label">Potential Revenue Loss</div>
          </div>
        </div>

        {/* Risk Distribution */}
        <div className="risk-distribution">
          <h4>Risk Level Distribution</h4>
          <div className="distribution-bars">
            {Object.entries(riskDistribution).map(([riskLevel, count]) => {
              const percentage = totalCustomers > 0 ? (count / totalCustomers * 100).toFixed(1) : 0;
              let barColor = "";
              
              if (riskLevel.includes("High")) barColor = "high-risk";
              else if (riskLevel.includes("Moderate")) barColor = "medium-risk";
              else barColor = "low-risk";

              return (
                <div key={riskLevel} className="distribution-item">
                  <div className="risk-label">{riskLevel}</div>
                  <div className="bar-container">
                    <div 
                      className={`risk-bar ${barColor}`}
                      style={{ width: `${percentage}%` }}
                    >
                      <span className="bar-count">{count} customers</span>
                    </div>
                  </div>
                  <div className="risk-percentage">{percentage}%</div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Sample Predictions */}
      <div className="section-card sample-predictions">
        <h3>📋 Sample Predictions (First 10 Customers)</h3>
        <div className="predictions-table">
          <table>
            <thead>
              <tr>
                <th>Customer</th>
                <th>Churn Probability</th>
                <th>Risk Level</th>
                <th>Prediction</th>
                <th>Recommendation</th>
              </tr>
            </thead>
            <tbody>
              {sample_predictions && sample_predictions.slice(0, 10).map((customer, index) => {
                const riskLevel = customer.Risk_Level || 'Unknown';
                let recommendation = '';
                
                if (riskLevel.includes('High')) {
                  recommendation = 'Immediate outreach + Exclusive offers';
                } else if (riskLevel.includes('Moderate')) {
                  recommendation = 'Proactive engagement + Loyalty program';
                } else {
                  recommendation = 'Maintain relationship + Upsell';
                }

                return (
                  <tr key={index}>
                    <td>Customer {index + 1}</td>
                    <td>
                      <div className="probability-bar">
                        <div 
                          className="probability-fill"
                          style={{ width: `${(customer.Churn_Probability || 0) * 100}%` }}
                        ></div>
                        <span className="probability-text">
                          {((customer.Churn_Probability || 0) * 100).toFixed(1)}%
                        </span>
                      </div>
                    </td>
                    <td>
                      <span className={`risk-badge ${riskLevel.toLowerCase().replace(' ', '-')}`}>
                        {riskLevel}
                      </span>
                    </td>
                    <td>
                      <span className={`prediction ${customer.Predicted_Churn ? 'churn' : 'no-churn'}`}>
                        {customer.Predicted_Churn ? "🚨 Churn" : "✅ Retain"}
                      </span>
                    </td>
                    <td>
                      <span className="recommendation-text">{recommendation}</span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Report Download Section */}
      <div className="section-card download-section">
        <h3>📥 Download Complete Analysis Report</h3>
        <div className="download-info">
          <div className="download-description">
            <h4>📊 Full Dataset Report</h4>
            <p><strong>Complete analysis of all {totalCustomers} customers with detailed predictions</strong></p>
            <div className="report-features">
              <div className="feature-list">
                <h5>✅ What's included in the report:</h5>
                <ul>
                  <li>All original customer data features</li>
                  <li>Churn probability percentages for each customer</li>
                  <li>Risk level classification (Low/Moderate/High)</li>
                  <li>Churn prediction (Yes/No)</li>
                  <li>Detailed retention recommendations</li>
                  <li>Customer IDs for easy reference</li>
                  <li>All calculated business metrics</li>
                  <li>Comprehensive summary statistics</li>
                </ul>
              </div>
            </div>
            <div className="download-actions">
              <button className="download-btn secondary" onClick={downloadSampleTemplate}>
                <span className="btn-icon">📋</span>
                Download CSV Template
              </button>
              <button 
                className="download-btn primary" 
                onClick={downloadFullDataset}
                disabled={downloadLoading}
              >
                {downloadLoading ? (
                  <>
                    <div className="spinner small"></div>
                    Downloading...
                  </>
                ) : (
                  <>
                    <span className="btn-icon">📥</span>
                    Download Complete Report (CSV)
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
        
        <div className="report-notice">
          <p>
            <strong>💡 Note:</strong> The Complete Report contains predictions for all {totalCustomers} customers 
            with complete feature data, risk levels, and actionable retention strategies. 
            {!uploadedFile && " Currently using demo data - upload your own CSV for custom analysis."}
          </p>
        </div>
      </div>
    </div>
  );
}

export default BatchDashboard;
